const input = $input.first().json;
const wordCount = input.word_count || 0;
const hasDoc = input.has_document || false;

return [{
  json: {
    ...input,
    mode: !hasDoc ? 'prompt_only' : (wordCount <= 10000 ? 'direct' : 'chunked'),
    chunk_count: wordCount > 10000 ? Math.ceil(wordCount / 10000) : 1
  }
}];

// Parse Gemini response → metadata
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

try {
  const metadata = JSON.parse(text);
  return [{ json: { chunk_index: $('Split Into Items').item.json.chunk_index, metadata } }];
} catch (e) {
  return [{ json: { chunk_index: 0, metadata: { headings: [], topics: [], key_entities: [], error: e.message } } }];
}

// Parse Gemini outline response (from either branch)
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

try {
  const result = JSON.parse(text);
  return [{ json: { analyst_result: result } }];
} catch (e) {
  throw new Error('Failed to parse outline JSON: ' + e.message);
}

// Prepare final output with chunks info
const analystResult = $input.first().json.analyst_result;
const originalInput = $('Detect Processing Mode').first().json;

return [{
  json: {
    job_id: originalInput.job_id,
    prompt: originalInput.prompt,
    analyst_result: analystResult,
    chunks: originalInput.mode === 'chunked' ? $('Agent: Split Chunks').first().json.chunks : [originalInput.document_text],
    mode: originalInput.mode,
    word_count: originalInput.word_count
  }
}];
